static const float POLICY_b2[8] = {0.09852097f, 0.07348829f, -0.01011566f, 0.09098302f, 0.03215453f, 0.00705894f, 0.06947462f, 0.12357894f};

static const float POLICY_MAX_DDELTA = 0.01500000f;  /* acceleration scale (rad/step) */
static const float POLICY_DELTA_LIMIT = 0.03000000f;  /* max |delta| (rad/step) */
static const float POLICY_TARGET_VX = 0.25000000f;  /* desired forward speed (m/s) */

static const float POLICY_JOINT_LO[8] = {0.300000f, -1.800000f, 0.300000f, -1.800000f, 0.300000f, -1.800000f, 0.300000f, -1.800000f};
static const float POLICY_JOINT_HI[8] = {1.500000f, -1.000000f, 1.500000f, -1.000000f, 1.500000f, -1.000000f, 1.500000f, -1.000000f};
static const float POLICY_OFFSETS[8]   = {0.900000f, -1.400000f, 0.900000f, -1.400000f, 0.900000f, -1.400000f, 0.900000f, -1.400000f};

static inline void policy_step(
    const float state[POLICY_STATE_DIM],
    float       ctrl [POLICY_ACTION_DIM],
    float       delta[POLICY_ACTION_DIM])
{
    int i, j, k;
    float h[POLICY_HIDDEN_DIM];
    for (i = 0; i < POLICY_HIDDEN_DIM; i++) {
        float acc = POLICY_b1[i];
        for (j = 0; j < POLICY_STATE_DIM; j++) acc += POLICY_W1[i][j] * state[j];
        h[i] = (acc > 0.0f) ? acc : 0.0f;
    }
    float action[POLICY_ACTION_DIM];
    for (k = 0; k < POLICY_ACTION_DIM; k++) {
        float acc = POLICY_b2[k];
        for (i = 0; i < POLICY_HIDDEN_DIM; i++) acc += POLICY_W2[k][i] * h[i];
        action[k] = tanhf(acc);
    }
    for (k = 0; k < POLICY_ACTION_DIM; k++) {
        delta[k] += action[k] * POLICY_MAX_DDELTA;
        if      (delta[k] >  POLICY_DELTA_LIMIT) delta[k] =  POLICY_DELTA_LIMIT;
        else if (delta[k] < -POLICY_DELTA_LIMIT) delta[k] = -POLICY_DELTA_LIMIT;
        ctrl[k] += delta[k];
        if      (ctrl[k] > POLICY_JOINT_HI[k]) ctrl[k] = POLICY_JOINT_HI[k];
        else if (ctrl[k] < POLICY_JOINT_LO[k]) ctrl[k] = POLICY_JOINT_LO[k];
    }
}
